          CurrentSumValidAlign_out1 <= beatSumValid;
        end
      end
    end

  always_ff @(posedge clk or posedge reset)
    begin : delayMatch_128_process
      if (reset == 1'b1) begin
        delayMatch_reg_128 <= '{81{1'b0}};
      end
      else begin
        if (enb) begin
          delayMatch_reg_128[0] <= CurrentSumValidAlign_out1;
          delayMatch_reg_128[32'sd80:32'sd1] <= delayMatch_reg_128[32'sd79:32'sd0];
        end
      end
    end

  assign CurrentSumValidAlign_out1_1 = delayMatch_reg_128[80];

  assign currentSumValid = CurrentSumValidAlign_out1_1;

endmodule  // BeatAccumulator

